   1→import { useCallback, useEffect, useMemo, useRef, useState } from "react";
   2→import Konva from "konva";
   3→import { Image as KonvaImage, Layer, Line, Rect, Stage, Text } from "react-konva";
   4→import { BarLoader } from "react-spinners";
   5→import { useQueryClient } from "@tanstack/react-query";
   6→import { saveJournal, saveJournalImage } from "../../../../API/Api";
   7→import { useAuth } from "../../../Context/useAuth";
   8→import { parseCanvasDoc } from "../../../utils/canvasDoc";
   9→import PieMenu from "./PieMenu";
  10→import styles from "./CanvasEditor.module.css";
  11→import "./canvas.css";
  12→
  13→const FONT_BRUSHES = {
  14→    serif: {label: "Typewriter", fontFamily: "\"Courier New\", \"Lucida Console\", monospace", fontStyle: "normal", preview: "Ink Tape"},
  15→    handwritten: {label: "Brush Script", fontFamily: "\"Comic Sans MS\", \"Bradley Hand\", cursive", fontStyle: "normal", preview: "Wild Brush"},
  16→    bold: {label: "Street Bold", fontFamily: "\"Trebuchet MS\", \"Gill Sans\", sans-serif", fontStyle: "bold", preview: "Tagline"},
  17→    serifDisplay: {label: "Poster Serif", fontFamily: "Georgia, \"Times New Roman\", serif", fontStyle: "normal", preview: "Headline"}
  18→};
  19→
  20→const FONT_STYLE_MAP = {
  21→    serif: "serif",
  22→    handwritten: "handwritten",
  23→    bold: "bold",
  24→    mono: "serif",
  25→    serifDisplay: "serifDisplay"
  26→};
  27→
  28→const GRID_SIZE = 24;
  29→const CANVAS_MAX_WIDTH = 560;
  30→const MOBILE_BREAKPOINT = 820;
  31→const MIN_VIEWPORT_SCALE = 0.85;
  32→const MAX_VIEWPORT_SCALE = 3;
  33→const OBJECT_LIFT_MULTIPLIER = 1.03;
  34→
  35→const COLOR_PALETTES = [
  36→    {label: "Pastels", colors: ["#f8c8dc", "#f9e2af", "#b7e4c7", "#bde0fe", "#d7c3ff"]},
  37→    {label: "Earth", colors: ["#8c5e3c", "#b7794b", "#5a6d4d", "#4d6f75", "#2f3e46"]},
  38→    {label: "Neon", colors: ["#ff2d55", "#ff7a00", "#f7ff00", "#00e5ff", "#8a2be2"]}
  39→];
  40→
  41→const DEFAULT_DOODLE_COLOR = COLOR_PALETTES[2].colors[0];
  42→
  43→const clamp = (value, min, max) => Math.min(Math.max(value, min), max);
  44→const createId = (prefix) => `${prefix}-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  45→const randomPlacement = () => ({
  46→    rotation: (Math.random() - 0.5) * 10,
  47→    xOffset: (Math.random() - 0.5) * 0.06,
  48→    yOffset: (Math.random() - 0.5) * 0.06
  49→});
  50→
  51→const sanitizeNormalizedPoints = (rawPoints) => {
  52→    if(!Array.isArray(rawPoints)){
  53→        return [];
  54→    }
  55→
  56→    const numericPoints = rawPoints
  57→        .map((point) => Number(point))
  58→        .filter((point) => !Number.isNaN(point))
  59→        .map((point) => clamp(point, 0, 1));
  60→
  61→    if(numericPoints.length < 2){
  62→        return [];
  63→    }
  64→
  65→    return numericPoints.length % 2 === 0 ? numericPoints : numericPoints.slice(0, -1);
  66→};
  67→
  68→const getStageHeight = (width, aspectRatio) => (aspectRatio === "4:5" ? Math.round(width * 1.25) : width);
  69→
  70→const getLegacyFontStyle = (fontStyle) => {
  71→    if(fontStyle === "mono"){
  72→        return "serif";
  73→    }
  74→    return FONT_STYLE_MAP[fontStyle] ? fontStyle : "serif";
  75→};
  76→
  77→const getSnippetMetrics = (snippet, stageWidth) => {
  78→    const sizeScale = Number.isFinite(snippet.sizeScale) ? snippet.sizeScale : 1;
  79→    const styleKey = FONT_STYLE_MAP[snippet.fontStyle] || "serif";
  80→    const baseFontSize = styleKey === "bold" ? 34 : styleKey === "handwritten" ? 32 : 30;
  81→    const fontSize = clamp(baseFontSize * sizeScale, 18, 92);
  82→    const estimatedWidth = Math.max(120, Math.min(stageWidth * 0.78, Math.round((snippet.text.length || 1) * fontSize * 0.58)));
  83→    const charsPerLine = Math.max(8, Math.floor(estimatedWidth / (fontSize * 0.56)));
  84→    const lineCount = Math.max(1, Math.ceil((snippet.text.length || 1) / charsPerLine));
  85→    const height = Math.max(68, Math.round(lineCount * fontSize * 1.14 + 18));
  86→    return {width: estimatedWidth, height, fontSize};
  87→};
  88→
  89→const constrainViewport = (candidate, stageWidth, stageHeight) => {
  90→    const scale = clamp(candidate?.scale || 1, MIN_VIEWPORT_SCALE, MAX_VIEWPORT_SCALE);
  91→    const scaledWidth = stageWidth * scale;
  92→    const scaledHeight = stageHeight * scale;
  93→    let minX = Math.min(0, stageWidth - scaledWidth);
  94→    let maxX = 0;
  95→    let minY = Math.min(0, stageHeight - scaledHeight);
  96→    let maxY = 0;
  97→
  98→    if(scaledWidth <= stageWidth){
  99→        const centeredX = (stageWidth - scaledWidth) / 2;
 100→        minX = centeredX;
 101→        maxX = centeredX;
 102→    }
 103→    if(scaledHeight <= stageHeight){
 104→        const centeredY = (stageHeight - scaledHeight) / 2;
 105→        minY = centeredY;
 106→        maxY = centeredY;
 107→    }
 108→
 109→    return {
 110→        scale,
 111→        x: clamp(candidate?.x || 0, minX, maxX),
 112→        y: clamp(candidate?.y || 0, minY, maxY)
 113→    };
 114→};
 115→
 116→const getTouchGeometry = (nativeEvent, stage) => {
 117→    const touches = nativeEvent?.touches;
 118→    if(!stage || !touches || touches.length < 2){
 119→        return null;
 120→    }
 121→
 122→    const bounds = stage.container()?.getBoundingClientRect();
 123→    if(!bounds){
 124→        return null;
 125→    }
 126→
 127→    const first = touches[0];
 128→    const second = touches[1];
 129→    const firstPoint = {x: first.clientX - bounds.left, y: first.clientY - bounds.top};
 130→    const secondPoint = {x: second.clientX - bounds.left, y: second.clientY - bounds.top};
 131→
 132→    return {
 133→        center: {x: (firstPoint.x + secondPoint.x) / 2, y: (firstPoint.y + secondPoint.y) / 2},
 134→        distance: Math.hypot(secondPoint.x - firstPoint.x, secondPoint.y - firstPoint.y)
 135→    };
 136→};
 137→
 138→const useLoadedImage = (src) => {
 139→    const [image, setImage] = useState(null);
 140→
 141→    useEffect(() => {
 142→        if(!src){
 143→            setImage(null);
 144→            return;
 145→        }
 146→
 147→        const img = new window.Image();
 148→        img.crossOrigin = "anonymous";
 149→        img.onload = () => setImage(img);
 150→        img.onerror = () => setImage(null);
 151→        img.src = src;
 152→
 153→        return () => {
 154→            img.onload = null;
 155→            img.onerror = null;
 156→        };
 157→    }, [src]);
 158→
 159→    return image;
 160→};
 161→
 162→const CanvasImageNode = ({
 163→    canvasImage,
 164→    stageWidth,
 165→    stageHeight,
 166→    isSelected,
 167→    isDragging,
 168→    onSelect,
 169→    onDragStart,
 170→    onDragEnd,
 171→    canInteract,
 172→    preventTouchDefault,
 173→    isBeingRemoved
 174→}) => {
 175→    const loadedImage = useLoadedImage(canvasImage?.src);
 176→    const objectWidth = clamp((canvasImage?.width || 0.3) * stageWidth, 56, stageWidth * 0.95);
 177→    const objectHeight = clamp((canvasImage?.height || 0.3) * stageHeight, 56, stageHeight * 0.95);
 178→    const x = clamp((canvasImage?.x || 0) * stageWidth, 0, Math.max(0, stageWidth - objectWidth));
 179→    const y = clamp((canvasImage?.y || 0) * stageHeight, 0, Math.max(0, stageHeight - objectHeight));
 180→    const liftMultiplier = isDragging ? OBJECT_LIFT_MULTIPLIER + 0.02 : isSelected ? OBJECT_LIFT_MULTIPLIER : 1;
 181→    const baseScaleX = canvasImage?.scaleX === -1 ? -1 : 1;
 182→
 183→    return (
 184→        <>
 185→            <KonvaImage
 186→                name={canvasImage?.id}
 187→                x={x}
 188→                y={y}
 189→                width={objectWidth}
 190→                height={objectHeight}
 191→                image={loadedImage}
 192→                draggable={canInteract && !isBeingRemoved}
 193→                rotation={canvasImage?.rotation || 0}
 194→                scaleX={baseScaleX * liftMultiplier}
 195→                scaleY={liftMultiplier}
 196→                shadowColor="rgba(0,0,0,0.3)"
 197→                shadowBlur={isSelected || isDragging ? 16 : 8}
 198→                shadowOffsetY={isSelected || isDragging ? 6 : 3}
 199→                preventDefault={preventTouchDefault}
 200→                onClick={canInteract ? onSelect : undefined}
 201→                onTap={canInteract ? onSelect : undefined}
 202→                onDragStart={onDragStart}
 203→                onDragEnd={onDragEnd}
 204→            />
 205→            {isSelected && (
 206→                <Rect
 207→                    x={x}
 208→                    y={y}
 209→                    width={objectWidth}
 210→                    height={objectHeight}
 211→                    stroke="#68d391"
 212→                    strokeWidth={1.7}
 213→                    dash={[6, 4]}
 214→                    rotation={canvasImage?.rotation || 0}
 215→                    listening={false}
 216→                />
 217→            )}
 218→        </>
 219→    );
 220→};
 221→
 222→const MINIMAP_WIDTH = 110;
 223→
 224→const CanvasMinimap = ({viewport, stageWidth, stageHeight, viewportWidth, viewportHeight, fitScale, isDark, updateViewport}) => {
 225→    const containerRef = useRef(null);
 226→    const dragRef = useRef(null);
 227→
 228→    const miniH = Math.round(MINIMAP_WIDTH * stageHeight / stageWidth);
 229→    const rectW = MINIMAP_WIDTH / viewport.scale;
 230→    const rectH = miniH / viewport.scale;
 231→    const rectX = -viewport.x * MINIMAP_WIDTH / (viewportWidth * viewport.scale);
 232→    const rectY = -viewport.y * miniH / (viewportHeight * viewport.scale);
 233→
 234→    const minimapToViewport = useCallback((mx, my) => {
 235→        const cx = mx * stageWidth / MINIMAP_WIDTH;
 236→        const cy = my * stageHeight / miniH;
 237→        return {
 238→            scale: viewport.scale,
 239→            x: viewportWidth / 2 - cx * fitScale * viewport.scale,
 240→            y: viewportHeight / 2 - cy * fitScale * viewport.scale
 241→        };
 242→    }, [viewport.scale, stageWidth, stageHeight, miniH, viewportWidth, viewportHeight, fitScale]);
 243→
 244→    const handleBackgroundClick = (e) => {
 245→        if(dragRef.current?.didDrag) return;
 246→        const rect = containerRef.current?.getBoundingClientRect();
 247→        if(!rect) return;
 248→        const mx = e.clientX - rect.left;
 249→        const my = e.clientY - rect.top;
 250→        updateViewport(minimapToViewport(mx, my));
 251→    };
 252→
 253→    const handleRectMouseDown = (e) => {
 254→        e.stopPropagation();
 255→        e.preventDefault();
 256→        const startClientX = e.clientX;
 257→        const startClientY = e.clientY;
 258→        const startRectX = rectX;
 259→        const startRectY = rectY;
 260→        dragRef.current = {didDrag: false};
 261→
 262→        const onMove = (moveEvent) => {
 263→            dragRef.current.didDrag = true;
 264→            const dx = moveEvent.clientX - startClientX;
 265→            const dy = moveEvent.clientY - startClientY;
 266→            const newRectX = startRectX + dx;
 267→            const newRectY = startRectY + dy;
 268→            updateViewport({
 269→                scale: viewport.scale,
 270→                x: -newRectX * viewportWidth * viewport.scale / MINIMAP_WIDTH,
 271→                y: -newRectY * viewportHeight * viewport.scale / miniH
 272→            });
 273→        };
 274→
 275→        const onUp = () => {
 276→            document.removeEventListener("mousemove", onMove);
 277→            document.removeEventListener("mouseup", onUp);
 278→            setTimeout(() => { dragRef.current = null; }, 0);
 279→        };
 280→
 281→        document.addEventListener("mousemove", onMove);
 282→        document.addEventListener("mouseup", onUp);
 283→    };
 284→
 285→    return (
 286→        <div
 287→            ref={containerRef}
 288→            className={`${styles.minimapContainer} ${isDark ? styles.minimapDark : ""}`}
 289→            style={{width: MINIMAP_WIDTH, height: miniH}}
 290→            onClick={handleBackgroundClick}
 291→        >
 292→            <div
 293→                className={styles.minimapViewport}
 294→                style={{
 295→                    left: clamp(rectX, 0, MINIMAP_WIDTH - Math.max(rectW, 4)),
 296→                    top: clamp(rectY, 0, miniH - Math.max(rectH, 4)),
 297→                    width: Math.max(rectW, 4),
 298→                    height: Math.max(rectH, 4)
 299→                }}
 300→                onMouseDown={handleRectMouseDown}
 301→            />
 302→        </div>
 303→    );
 304→};
