 306→const CanvasEditor = ({title, onCloseOnSave, addUploadedImagePath, initialCanvasDoc = null, remixSource = null}) => {
 307→    const {session, user} = useAuth();
 308→    const queryClient = useQueryClient();
 309→    const shellRef = useRef(null);
 310→    const ambientLightRef = useRef(null);
 311→    const stageFrameRef = useRef(null);
 312→    const stageRef = useRef(null);
 313→    const hasHydratedInitialDocRef = useRef(false);
 314→    const snippetInputRef = useRef(null);
 315→    const doodlePointsRef = useRef([]);
 316→    const viewportRef = useRef({scale: 1, x: 0, y: 0});
 317→    const pinchStateRef = useRef({isActive: false, lastDistance: 0, lastCenter: null});
 318→    const [shellWidth, setShellWidth] = useState(CANVAS_MAX_WIDTH);
 319→
 320→    const [activeTool, setActiveTool] = useState("select");
 321→    const [isSnippetComposerOpen, setIsSnippetComposerOpen] = useState(false);
 322→    const [snippetInput, setSnippetInput] = useState("");
 323→    const [selectedObject, setSelectedObject] = useState(null);
 324→    const [draggingObject, setDraggingObject] = useState(null);
 325→    const [isSending, setIsSending] = useState(false);
 326→    const [isUploadingImage, setIsUploadingImage] = useState(false);
 327→    const [doodleColor, setDoodleColor] = useState(DEFAULT_DOODLE_COLOR);
 328→    const [doodleSize, setDoodleSize] = useState(2.8);
 329→    const [isDrawing, setIsDrawing] = useState(false);
 330→    const [currentDoodlePoints, setCurrentDoodlePoints] = useState([]);
 331→    const [canvasMeta, setCanvasMeta] = useState({
 332→        aspectRatio: "1:1",
 333→        gridEnabled: true,
 334→        snapEnabled: true,
 335→        theme: "light"
 336→    });
 337→    const [snippets, setSnippets] = useState([]);
 338→    const [images, setImages] = useState([]);
 339→    const [doodles, setDoodles] = useState([]);
 340→    const [viewport, setViewport] = useState({scale: 1, x: 0, y: 0});
 341→    const [isMobileViewport, setIsMobileViewport] = useState(false);
 342→    const [isMobileDockOpen, setIsMobileDockOpen] = useState(false);
 343→    const [isDoodleDockMinimized, setIsDoodleDockMinimized] = useState(false);
 344→    const [animatingRemovalId, setAnimatingRemovalId] = useState(null);
 345→    const [doodleRedoStack, setDoodleRedoStack] = useState([]);
 346→    const multiTapRef = useRef({fingerCount: 0, timestamp: 0});
 347→    const longPressRef = useRef(null);
 348→    const [pieMenu, setPieMenu] = useState({isOpen: false, position: null, items: []});
 349→
 350→    const updateSnippet = (snippetId, updater) => {
 351→        setSnippets((prev) => prev.map((snippet) => {
 352→            if(snippet.id !== snippetId){
 353→                return snippet;
 354→            }
 355→            const nextValue = typeof updater === "function" ? updater(snippet) : updater;
 356→            return {...snippet, ...nextValue};
 357→        }));
 358→    };
 359→
 360→    const updateImage = (imageId, updater) => {
 361→        setImages((prev) => prev.map((image) => {
 362→            if(image.id !== imageId){
 363→                return image;
 364→            }
 365→            const nextValue = typeof updater === "function" ? updater(image) : updater;
 366→            return {...image, ...nextValue};
 367→        }));
 368→    };
 369→
 370→    useEffect(() => {
 371→        if(hasHydratedInitialDocRef.current || !initialCanvasDoc){
 372→            return;
 373→        }
 374→
 375→        const parsedDoc = parseCanvasDoc(initialCanvasDoc);
 376→        setCanvasMeta((prev) => ({
 377→            ...prev,
 378→            aspectRatio: parsedDoc?.meta?.aspectRatio === "4:5" ? "4:5" : "1:1",
 379→            gridEnabled: Boolean(parsedDoc?.meta?.gridEnabled),
 380→            theme: parsedDoc?.meta?.theme === "dark" ? "dark" : "light"
 381→        }));
 382→        setSnippets((parsedDoc?.snippets || []).map((snippet) => ({
 383→            ...snippet,
 384→            id: snippet.id || createId("snippet"),
 385→            fontStyle: getLegacyFontStyle(snippet.fontStyle),
 386→            zIndex: Number.isFinite(snippet?.zIndex) ? snippet.zIndex : 0
 387→        })));
 388→        setImages((parsedDoc?.images || []).map((image) => ({
 389→            ...image,
 390→            id: image.id || createId("image"),
 391→            zIndex: Number.isFinite(image?.zIndex) ? image.zIndex : 0
 392→        })));
 393→        setDoodles((parsedDoc?.doodles || []).map((doodle) => ({
 394→            ...doodle,
 395→            id: doodle.id || createId("doodle"),
 396→            points: sanitizeNormalizedPoints(doodle.points)
 397→        })));
 398→        hasHydratedInitialDocRef.current = true;
 399→    }, [initialCanvasDoc]);
 400→
 401→    useEffect(() => {
 402→        const getContentWidth = () => {
 403→            const element = shellRef.current;
 404→            if(!element){
 405→                return CANVAS_MAX_WIDTH;
 406→            }
 407→            const computedStyle = getComputedStyle(element);
 408→            const paddingLeft = parseFloat(computedStyle.paddingLeft) || 0;
 409→            const paddingRight = parseFloat(computedStyle.paddingRight) || 0;
 410→            return Math.max(0, element.clientWidth - paddingLeft - paddingRight);
 411→        };
 412→
 413→        const updateShellWidth = () => {
 414→            setShellWidth(getContentWidth());
 415→        };
 416→
 417→        updateShellWidth();
 418→        window.addEventListener("resize", updateShellWidth);
 419→
 420→        let resizeObserver = null;
 421→        if(typeof ResizeObserver !== "undefined" && shellRef.current){
 422→            resizeObserver = new ResizeObserver(updateShellWidth);
 423→            resizeObserver.observe(shellRef.current);
 424→        }
 425→
 426→        return () => {
 427→            window.removeEventListener("resize", updateShellWidth);
 428→            if(resizeObserver){
 429→                resizeObserver.disconnect();
 430→            }
 431→        };
 432→    }, []);
 433→
 434→    useEffect(() => {
 435→        const mediaQuery = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT}px)`);
 436→        const syncViewport = () => setIsMobileViewport(mediaQuery.matches);
 437→        syncViewport();
 438→
 439→        if(typeof mediaQuery.addEventListener === "function"){
 440→            mediaQuery.addEventListener("change", syncViewport);
 441→            return () => mediaQuery.removeEventListener("change", syncViewport);
 442→        }
 443→
 444→        mediaQuery.addListener(syncViewport);
 445→        return () => mediaQuery.removeListener(syncViewport);
 446→    }, []);
 447→
 448→    useEffect(() => {
 449→        if(isMobileViewport){
 450→            setIsMobileDockOpen(false);
 451→            return;
 452→        }
 453→        setIsMobileDockOpen(true);
 454→    }, [isMobileViewport]);
 455→
 456→    useEffect(() => {
 457→        if(!isSnippetComposerOpen){
 458→            return;
 459→        }
 460→        const frame = window.requestAnimationFrame(() => snippetInputRef.current?.focus());
 461→        return () => window.cancelAnimationFrame(frame);
 462→    }, [isSnippetComposerOpen]);
 463→
 464→    useEffect(() => {
 465→        if(activeTool !== "doodle"){
 466→            doodlePointsRef.current = [];
 467→            setCurrentDoodlePoints([]);
 468→            setIsDrawing(false);
 469→            setIsDoodleDockMinimized(false);
 470→        }
 471→    }, [activeTool]);
 472→
 473→    const viewportWidth = useMemo(() => Math.max(280, Math.min(CANVAS_MAX_WIDTH, shellWidth)), [shellWidth]);
 474→    const viewportHeight = getStageHeight(viewportWidth, canvasMeta.aspectRatio);
 475→    const stageWidth = CANVAS_MAX_WIDTH;
 476→    const stageHeight = getStageHeight(stageWidth, canvasMeta.aspectRatio);
 477→    const fitScale = viewportWidth > 0 ? viewportWidth / stageWidth : 1;
 478→    const fitOffsetX = (viewportWidth - stageWidth * fitScale) / 2;
 479→    const fitOffsetY = (viewportHeight - stageHeight * fitScale) / 2;
 480→
 481→    const updateViewport = (updater) => {
 482→        setViewport((prev) => {
 483→            const nextValue = typeof updater === "function" ? updater(prev) : updater;
 484→            const constrained = constrainViewport(nextValue, viewportWidth, viewportHeight);
 485→            viewportRef.current = constrained;
 486→            return constrained;
 487→        });
 488→    };
 489→
 490→    useEffect(() => {
 491→        viewportRef.current = viewport;
 492→    }, [viewport]);
 493→
 494→    useEffect(() => {
 495→        setViewport((prev) => constrainViewport(prev, viewportWidth, viewportHeight));
 496→    }, [viewportWidth, viewportHeight]);
 497→
 498→    useEffect(() => {
 499→        const safePixelRatio = clamp(window.devicePixelRatio || 1, 1, 2.5);
 500→        const stage = stageRef.current;
 501→        if(!stage){
 502→            return;
 503→        }
 504→
 505→        const previousRatio = Konva.pixelRatio;
 506→        Konva.pixelRatio = safePixelRatio;
 507→        stage.getLayers().forEach((layer) => {
 508→            const canvas = layer?.getCanvas?.();
 509→            if(canvas?.setPixelRatio){
 510→                canvas.setPixelRatio(safePixelRatio);
 511→            }
 512→        });
 513→        stage.batchDraw();
 514→        return () => {
 515→            Konva.pixelRatio = previousRatio;
 516→        };
 517→    }, [viewportWidth, viewportHeight]);
 518→
 519→    const getNextZIndex = () => {
 520→        const allZ = [
 521→            ...snippets.map((snippet) => snippet.zIndex || 0),
 522→            ...images.map((image) => image.zIndex || 0)
 523→        ];
 524→        return allZ.length ? Math.max(...allZ) + 1 : 0;
 525→    };
 526→
 527→    const sortedObjects = useMemo(() => {
 528→        const snippetObjects = snippets.map((snippet) => ({kind: "snippet", payload: snippet}));
 529→        const imageObjects = images.map((image) => ({kind: "image", payload: image}));
 530→        return [...snippetObjects, ...imageObjects].sort((a, b) => (a.payload?.zIndex || 0) - (b.payload?.zIndex || 0));
 531→    }, [snippets, images]);
 532→
 533→    const selectedSnippet = selectedObject?.kind === "snippet"
 534→        ? snippets.find((snippet) => snippet.id === selectedObject.id) || null
 535→        : null;
 536→    const canEditObjects = activeTool === "select";
 537→    const isDockVisible = !isMobileViewport || isMobileDockOpen;
 538→    const isDoodleMode = activeTool === "doodle";
 539→    const shouldPreventTouchDefault = isDoodleMode;
 540→    const showMinimizedDoodleDock = isDockVisible && isDoodleMode && isDoodleDockMinimized;
 541→    const hasCanvasContent = snippets.length > 0 || images.length > 0 || doodles.length > 0;
 542→
 543→    const addSnippet = () => {
 544→        const trimmed = snippetInput.trim();
 545→        if(!trimmed){
 546→            return;
 547→        }
 548→
 549→        const jitter = randomPlacement();
 550→        const snippet = {
 551→            id: createId("snippet"),
 552→            text: trimmed,
 553→            x: clamp(0.16 + jitter.xOffset, 0.02, 0.82),
 554→            y: clamp(0.2 + jitter.yOffset, 0.02, 0.82),
 555→            rotation: jitter.rotation,
 556→            fontStyle: "serif",
 557→            scaleX: 1,
 558→            sizeScale: 1,
