215→.toolbar-color-trigger:hover {
216→    background-color: var(--bg-pill);
217→}
218→.toolbar-color-icon {
219→    font-weight: 700;
220→    font-size: 0.9rem;
221→    line-height: 1;
222→}
223→.toolbar-color-swatch {
224→    width: 16px;
225→    height: 4px;
226→    border-radius: 3px;
227→    border: 1px solid var(--editor-border);
228→}
229→.color-popover {
230→    position: absolute;
231→    top: calc(100% + 6px);
232→    left: 0;
233→    display: grid;
234→    grid-template-columns: repeat(6, 18px);
235→    gap: 6px;
236→    padding: 8px;
237→    background: var(--editor-bg);
238→    border: 1px solid var(--editor-border);
239→    border-radius: 8px;
240→    box-shadow: var(--shadow-modal);
241→    z-index: 12;
242→}
243→.color-swatch {
244→    width: 18px;
245→    height: 18px;
246→    border-radius: 4px;
247→    border: 1px solid var(--editor-border);
248→    cursor: pointer;
249→    background-color: transparent;
250→}
251→.color-swatch.is-default {
252→    background-image:
253→        linear-gradient(45deg, rgba(0, 0, 0, 0.15) 25%, transparent 25%),
254→        linear-gradient(-45deg, rgba(0, 0, 0, 0.15) 25%, transparent 25%),
255→        linear-gradient(45deg, transparent 75%, rgba(0, 0, 0, 0.15) 75%),
256→        linear-gradient(-45deg, transparent 75%, rgba(0, 0, 0, 0.15) 75%);
257→    background-size: 6px 6px;
258→    background-position: 0 0, 0 3px, 3px -3px, -3px 0px;
259→}
260→.color-swatch.is-selected {
261→    outline: 2px solid var(--editor-accent);
262→    outline-offset: 1px;
263→}
264→
265→/* ── Editor shell (flex-grow, scrollable) ── */
266→.editor-shell {
267→    position: relative;
268→    flex: 1;
269→    min-height: 0;
270→    overflow-y: auto;
271→    overflow-x: auto;
272→    scrollbar-width: thin;
273→    scrollbar-color: var(--text-muted) transparent;
274→}
275→.editor-shell::-webkit-scrollbar {
276→    width: 6px;
277→}
278→.editor-shell::-webkit-scrollbar-thumb {
279→    background: var(--text-muted);
280→    border-radius: 4px;
281→}
282→.editor-shell::-webkit-scrollbar-track {
283→    background-color: transparent;
284→}
285→
286→/* ── Editor content area ── */
287→.editor-text-container {
288→    white-space: pre-wrap;
289→    color: var(--editor-text);
290→    padding: 1rem 0.5rem;
291→}
292→.editor-input:focus {
293→    outline: none;
294→}
295→.editor-placeholder {
296→    color: var(--text-muted);
297→    overflow: hidden;
298→    position: absolute;
299→    top: -4px;
300→    user-select: none;
301→    pointer-events: none;
302→    margin: 0;
303→}
304→.editor-paragraph {
305→    margin: 0;
306→}
307→.editor-heading-h1 {
308→    margin: 0.9rem 0 0.45rem;
309→    font-size: 1.75rem;
310→    font-weight: 700;
311→    line-height: 1.25;
312→    color: var(--text-heading);
313→}
314→.editor-heading-h2 {
315→    margin: 0.8rem 0 0.4rem;
316→    font-size: 1.4rem;
317→    font-weight: 650;
318→    line-height: 1.3;
319→    color: var(--text-heading);
320→}
321→.editor-heading-h3 {
322→    margin: 0.7rem 0 0.35rem;
323→    font-size: 1.15rem;
324→    font-weight: 600;
325→    line-height: 1.35;
326→    color: var(--text-heading);
327→}
328→.editor-quote {
329→    margin: 0.5rem 0;
330→    padding: 0.3rem 0.65rem;
331→    border-left: 2px solid var(--editor-accent);
332→    background: color-mix(in srgb, var(--editor-accent) 5%, transparent);
333→    color: var(--editor-text);
334→    font-style: italic;
335→}
336→
337→/* ── Footer bar (word count + save) ── */
338→.editor-footer {
339→    display: flex;
340→    justify-content: space-between;
341→    align-items: center;
342→    padding: 0.5rem 0;
343→    border-top: 1px solid var(--editor-border);
344→    margin-top: auto;
345→}
346→.editor-word-count {
347→    font-size: 0.8rem;
348→    color: var(--text-muted);
349→    user-select: none;
350→    padding-left: 0.25rem;
351→}
352→
353→/* ── Bar loader positioning ── */
354→.editor-loader-wrapper {
355→    height: 4px;
356→    flex-shrink: 0;
357→}
358→
359→/* ── Save button ── */
360→.editor-save-bttn {
361→    display: flex;
362→    justify-content: center;
363→    align-items: center;
364→    padding: 0.5rem 1.25rem;
365→    border-radius: 15px;
366→    background-color: var(--editor-accent);
367→    color: #ffffff;
368→    font-weight: 650;
369→    cursor: pointer;
370→    border: none;
371→    transition: background-color 0.15s ease, transform 0.1s ease, opacity 0.15s ease;
372→}
373→.editor-save-bttn:hover {
374→    opacity: 0.9;
375→}
376→.editor-save-bttn:active {
377→    transform: scale(0.98);
378→}
379→.editor-save-bttn:focus {
380→    outline: none;
381→}
382→.editor-save-bttn-disabled {
383→    display: flex;
384→    justify-content: center;
385→    align-items: center;
386→    padding: 0.5rem 1.25rem;
387→    border-radius: 15px;
388→    background-color: var(--bg-pill);
389→    color: var(--text-muted);
390→    font-weight: 650;
391→    user-select: none;
392→    border: none;
393→    cursor: not-allowed;
394→}
395→.editor-save-bttn-disabled:focus {
396→    outline: none;
397→}
398→
399→.composer-mode-btn{
400→    display: inline-flex;
401→    align-items: center;
402→    gap: 0.35rem;
403→    font-weight: 600;
404→}
405→
406→/* ── Image upload icon (inside toolbar) ── */
407→.editor-upload-image-icon {
408→    padding: 0.4rem;
409→    border-radius: 6px;
410→    cursor: pointer;
411→    transition: all 0.15s ease;
412→}
413→.editor-upload-image-icon:hover {
414→    background-color: var(--bg-pill);
415→}
416→
417→/* ── Image components ── */
418→.image-container {
419→    display: flex;
420→    justify-content: center;
421→    width: 100%;
422→    height: fit-content;
423→}
424→.image-wrapper {
425→    position: relative;
426→    display: flex;
427→    justify-content: flex-end;
428→    margin: 1rem 0;
429→    width: fit-content;
430→    height: fit-content;
431→}
432→.image-actions {
433→    position: absolute;
434→    display: flex;
435→    gap: 0.3rem;
436→    top: 0;
437→    right: 0;
438→    margin: 0.5rem;
439→    z-index: 11;
440→}
441→.image-action-btn {
442→    display: flex;
443→    align-items: center;
444→    justify-content: center;
445→    padding: 0.4rem;
446→    border-radius: 50%;
447→    cursor: pointer;
448→    transition: ease-in-out 0.1s;
449→    background-color: rgba(0, 0, 0, 0.35);
450→}
451→.image-action-btn:hover {
452→    background-color: rgba(0, 0, 0, 0.55);
453→}
454→.dimension-display {
455→    position: absolute;
456→    display: flex;
457→    justify-content: center;
458→    align-items: center;
459→    top: -35px;
460→    left: 50%;
461→    transform: translateX(-50%);
462→    background-color: var(--bg-pill);
463→    color: var(--text-muted);
464→    padding: 0.4rem 0.5rem;
465→    white-space: nowrap;
466→    pointer-events: none;
467→    font-size: 0.8rem;
468→    border-radius: 4px;
469→}
470→
471→/* ── Resize handles ── */
472→.southeast-side-handle {
473→    position: absolute;
474→    bottom: -4px;
475→    right: -4px;
476→    width: 12px;
477→    height: 12px;
478→    background-color: var(--bg-pill);
479→    border: 1px solid var(--editor-text);
480→    border-radius: 50%;
481→    cursor: nwse-resize;
482→    z-index: 10;
483→}
484→.southwest-side-handle {
485→    position: absolute;
486→    bottom: -4px;
487→    left: -4px;
488→    width: 12px;
489→    height: 12px;
490→    background-color: var(--bg-pill);
491→    border: 1px solid var(--editor-text);
492→    border-radius: 50%;
493→    cursor: nesw-resize;
494→    z-index: 10;
495→}
496→.northeast-side-handle {
497→    position: absolute;
498→    top: -4px;
499→    right: -4px;
500→    width: 12px;
501→    height: 12px;
502→    background-color: var(--bg-pill);
503→    border: 1px solid var(--editor-text);
504→    border-radius: 50%;
505→    cursor: sw-resize;
506→    z-index: 10;
507→}
508→.northwest-side-handle {
509→    position: absolute;
510→    top: -4px;
511→    left: -4px;
512→    width: 12px;
513→    height: 12px;
514→    background-color: var(--bg-pill);
515→    border: 1px solid var(--editor-text);
516→    border-radius: 50%;
517→    cursor: se-resize;
518→    z-index: 10;
519→}
520→.east-side-handle {
521→    position: absolute;
522→    top: 50%;
523→    right: -4px;
524→    width: 8px;
525→    height: 20px;
526→    background-color: var(--bg-pill);
527→    border: 1px solid var(--editor-text);
528→    border-radius: 2px;
529→    transform: translateY(-50%);
530→    cursor: ew-resize;
531→    z-index: 10;
532→}
533→.south-side-handle {
534→    position: absolute;
535→    bottom: -4px;
536→    left: 50%;
537→    width: 20px;
538→    height: 8px;
539→    background-color: var(--bg-pill);
540→    border: 1px solid var(--editor-text);
541→    border-radius: 2px;
542→    transform: translateX(-50%);
543→    cursor: ns-resize;
544→    z-index: 10;
545→}
546→.north-side-handle {
547→    position: absolute;
548→    top: -4px;
549→    left: 50%;
550→    width: 20px;
551→    height: 8px;
552→    background-color: var(--bg-pill);
553→    border: 1px solid var(--editor-text);
554→    border-radius: 2px;
555→    transform: translateX(-50%);
556→    cursor: nw-resize;
557→    z-index: 10;
558→}
559→
560→/* ── Image loading overlay ── */
561→.image-loading-overlay {
562→    position: absolute;
563→    top: 0;
564→    left: 0;
565→    width: 100%;
566→    height: 100%;
567→    display: flex;
568→    flex-direction: column;
569→    justify-content: center;
570→    align-items: center;
571→    background-color: rgba(0, 0, 0, 0.45);
572→    border-radius: 5px;
573→    gap: 8px;
574→    pointer-events: none;
575→}
576→.image-loading-spinner {
577→    width: 28px;
578→    height: 28px;
579→    border: 3px solid rgba(255, 255, 255, 0.2);
580→    border-top: 3px solid var(--editor-accent);
581→    border-radius: 50%;
582→    animation: image-spin 0.8s linear infinite;
583→}
584→@keyframes image-spin {
585→    0% { transform: rotate(0deg); }
586→    100% { transform: rotate(360deg); }
587→}
588→
589→/* ── Full-screen image view ── */
590→.image-view {
591→    position: fixed;
592→    top: 0;
593→    left: 0;
594→    width: 100vw;
595→    height: 100vh;
596→    object-fit: contain;
597→    background: rgba(0, 0, 0, 0.7);
598→    z-index: 9999;
599→    cursor: zoom-out;
600→    box-sizing: border-box;
601→}
602→
603→/* ── Mobile responsive (overrides only) ── */
604→@media (max-width: 640px) {
