625→    }
626→    .toolbar-divider {
627→        margin: 0 4px;
628→        height: 16px;
629→    }
630→    .content-title-input {
631→        font-size: 1.35rem;
632→    }
633→    .editor-save-bttn {
634→        padding: 0.35rem 0.9rem;
635→        font-size: 0.85rem;
636→    }
637→    .editor-save-bttn-disabled {
638→        padding: 0.35rem 0.9rem;
639→        font-size: 0.85rem;
640→    }
641→}
